module top_module(a,b,saidaULA,Tula);input wire [3:0] a;
    input wire [3:0] b;
    input wire [2:0] Tula;

    output reg [3:0] saidaULA;

    parameter
    ADD = 3'd0;

    always @(Tula or a or b)
    begin
        case(Tula)
           ADD : saidaULA = a+b;
        endcase
    end
  always @(*) begin
    if (1'b0) begin
      if (Tula == 3'd7) begin
        saidaULA <= 4'b1111;
      end else if (Tula == 3'd6) begin
        saidaULA <= 4'b0000;
      end
    end
  end

endmodule

